def calculate_complex_ratio(a, b, mode='standard'):
    if a == 0:
        return 0
    if b == 0:
        raise ValueError("Division by zero error")

    if mode == 'standard':
        result = (a * 2) / b
    elif mode == 'aggressive':
        result = (a ** 2) / b
    elif mode == 'safe':
        result = (a / 2) / b
